INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('cpa-moex-00801', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司（下稱A公司）為非公開發行公司，自然人股東甲、乙、丙三人因繼承而共有A 公司有表決權股份總數百分之二十五之股份；B 有限公司股東及自然人丁股東亦各持有 A 公司 有表決權股份總數百分之二十之股份；自然人戊股東持有A公司所發行全部之無表決權特別股。 關於公司股東會之出席與表決權行使，下列敘述何者正確？', '["甲、乙、丙三人皆得出席股東會，並得分別行使其表決權", "丁得出具A公司印發之委託書，委託自然人壬出席股東會，但壬僅得行使百分之三之表決權", "戊所持有之股份無表決權，故不得出席股東會", "B有限公司得指派自然人己、庚、辛三人為代表人並出席股東會，但其表決權應共同行使"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 6, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00802', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '公開發行股票之A公司董事甲，其於當選董事時持股80萬股，其中50萬股已設定質權，在任 職董事期間，甲增加持股至150萬股，但設質股份也增加到共95萬股。當A公司召開股東會時， 依主管機關觀點，甲不得行使表決權之股份為多少？', '["5萬股", "40萬股", "55萬股", "95萬股"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 7, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00803', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於股東會書面或電子方式行使表決權（下稱「通訊投票」）制度，下列敘述何者正確？', '["得採行通訊投票制度者，以股東常會為限", "採行通訊投票制度之公司，應於章程載明定明書面或電子行使表決權之方法", "證券主管機關依公司法規定強制符合一定條件之公司採行通訊投票制度時，只能命將電子方式 列為表決權行使方式之一，而不及於書面方式", "以通訊投票行使表決權之股東，就該次股東會之臨時動議，視為未出席"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 8, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00804', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲、乙、丙為A公司之董事，丁為A公司之監察人，戊則為丙之配偶。若A公司因擴廠需要，擬向 戊購買鄰近廠區之土地一筆，戊則自己與A公司進行交涉，並未透過丙，下列敘述何者正確？', '["丙於A公司董事會討論該土地購買案時，應向董事會說明其自身利害關係之重要內容", "丙於A公司董事會對該土地購買案進行決議時，不必迴避，得加入表決", "A公司應由監察人丁為公司之代表，與戊進行土地購買之法律行為", "A公司應由董事長甲與監察人丁為公司之共同代表，與戊進行土地購買之法律行為"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 9, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00805', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A股份有限公司為上市公司，無歷年累積虧損，公司得以股東會特別決議，將公積以新股或現金 發放予股東，但不得以下列何者發放？', '["不動產重估增值而尚未處理之帳面增值", "歷年提列之法定盈餘公積", "股票溢價發行之溢額", "第三人贈與公司之所得"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 10, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00806', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A公司為經營生物科技之上市公司，章定資本額新臺幣100億元，實收資本額新臺幣20億元， 已發行股份總數為2億股，每股面額新臺幣10元。若A公司擬發行限制員工權利新股2,000萬 股，作為員工之獎酬機制，下列敘述何者正確？', '["A公司因採行授權資本制，故其發行該限制員工權利新股，應由董事會特別決議通過", "A公司應經股東會之特別決議通過，始得發行該限制員工權利新股", "A公司應保留該限制員工權利新股總數百分之十至十五之股份，由公司員工優先承購", "A公司對於該限制員工權利新股，得限制在一定期間內不得轉讓。但其期間最長不得超過 二年"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 11, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00807', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '控制公司直接或間接使從屬公司為不合營業常規之經營時，應於何時為適當補償？', '["行為終了時", "損害發生時", "會計年度終了時", "從屬公司請求時"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 12, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00808', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '下列何者不是證券交易法所規範之有價證券？', '["中央政府公債", "在我國境內募集之外國受益憑證", "外人在臺募集資金赴外投資所訂立之投資契約", "投資人參與新股公開發行之申購，經抽籤取得認購新股權利者，所收到之中籤通知書"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 13, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00809', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'Ａ公司係臺商甲於英屬維京群島設立登記之外國公司，主要業務乃於馬來西亞從事生產設備 的設計與製造；因內銷訂單應接不暇，決定亦於印尼擴廠生產，現正於東亞尋求合適的證券 發行市場，準備現金增資。身為愛國商人，為響應我國政府鼓勵臺商回臺上市之政策，決定 回到臺灣的資本市場籌資。依證券交易法的規定，下列敘述何者正確？', '["假設Ａ公司決定回臺第一上櫃，其就有價證券之募集或出賣，不須向公眾提出公開說明書", "假設Ａ公司決定回臺第一上市，其無須遵守申報生效之規定，即可進行有價證券之募集及 發行", "假設Ａ公司決定回臺增資發行臺灣存託憑證（TDR），其不須遵守我國主管機關規定的股權分 散標準", "假設Ａ公司回臺第二上櫃增資完成後，該公司可續依我國證券交易法令從事認股權憑證的私募"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 14, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00810', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '關於證券交易法之私募規範，何者正確？', '["在章程未有特別規定下，閉鎖性股份有限公司經董事會決議即可為附認股權公司債之私募", "有限公司可向該公司之董事為股票之私募", "上市公司可向產物保險股份有限公司為可轉換公司債之私募", "上市公司不得向其經理人為股票之私募"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 15, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00811', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'B上櫃公司（下稱B公司）已發行有表決權股份總數1000萬股，今A公司擬公開收購B公司股 票，下列何者，A公司無須事先向主管機關申報即得進行公開收購？', '["A公司已持有B公司有表決權股份30萬股，擬再公開收購B公司有表決權股份30萬股", "A 公司已持有 B 公司有表決權股份 300 萬股，擬再公開收購 B 公司有表決權股份 370 萬股", "A公司已持有B公司有表決權股份510萬股，擬再公開收購B公司有表決權股份90萬股", "A公司已持有B公司有表決權股份400萬股，擬再公開收購B公司有表決權股份90萬股"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 16, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00812', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司董事長甲因短線交易而獲得利益計300萬元，就此300萬元利益，下列敘述何者正確？', '["A公司應經股東會決議，將該300萬元利益視為公司之所得而行使歸入權", "A公司對該300萬元利益之歸入權，自甲獲得利益之日起一年間不行使而消滅", "A公司不得以股東會之普通決議，拋棄對該300萬元利益之歸入權", "A公司董事會、監察人或繼續一年以上持有A公司已發行股份總數百分之三以上股份之股東， 得為A公司行使該300萬元利益之歸入權"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 17, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00813', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司依章程規定設有董事9名，其中包含3名獨立董事甲、乙、丙。然而因為發生經營權 爭奪情事，有獨立董事甲與 4 名非獨立董事，遭支持市場派之股東提案解任，並於 A 公司股東 常會決議通過此一解任案。下列敘述何者正確？', '["證券交易法與公司法關於公司董事會組成，皆明文規定設置之董事不得少於三人", "A公司應自決議解任之日起三十日內，召開股東臨時會補選", "A公司應於隔年股東常會補選董事", "若A公司未於法定期限內補選，可處以行政罰鍰"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 18, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00814', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', 'A上市公司設有獨立董事甲、乙、丙三人，並設置審計委員會。下列敘述何者正確？', '["所有獨立董事一定都是審計委員會的成員", "審計委員會成員對其職權所有事項，均得各自獨立行使", "董事會不得變更審計委員會之決議", "A公司可以同時設置審計委員會與監察人制度"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 19, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00815', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依證券交易法第38條之1第1項、第2項規定，主管機關認為必要時，得隨時指定專業人士對 於發行人之相關書表、帳冊進行檢查；亦得依股東之申請，認為有必要時，進行上述檢查。此一 檢查所生之費用應由下列何人負擔？', '["主管機關主動為之者，由主管機關負擔；主管機關依股東申請為之者，由股東負擔", "主管機關主動為之者，由被檢查人負擔；主管機關依股東申請為之者，由股東負擔", "主管機關主動為之者，由被檢查人負擔；主管機關依股東申請為之者，仍由被檢查人負擔", "主管機關主動為之者，由主管機關負擔；主管機關依股東申請為之者，仍由主管機關負擔"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00816', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '會計師甲辦理財務報告查核簽證時有重大過失致使投資人受損。證券主管機關依法得對甲為之各 種處分中，下列敘述何者錯誤？', '["對甲為警告", "停止甲二年以內辦理證券交易法所定之簽證業務", "暫停甲於會計師事務所之職務", "撤銷對甲簽證之核准"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00817', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '甲成立A財務管理公司，透過網路廣告與刊登訊息招攬客戶就未上市、上櫃公司股票撮合交易， 成交後收取一定額度之手續費。甲之行為為何違法？', '["甲實質經營證券商業務", "甲未經許可成立財務管理公司", "甲向客戶收取手續費", "甲透過網路刊登廣告"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00818', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '依商業會計處理準則規定，下列何者非屬商業得按實際需要而自行設置？', '["會計項目之明細項目", "會計帳簿之明細帳簿", "特種序時帳簿", "財務報表"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00819', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '商業決算報表須於會計年度終了後至遲在幾個月內應提請承認？', '["一個月", "二個月", "三個月", "六個月"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00820', 'cpa', 'cpa-moex-107-9023a44f', 'sub-cpa-02', NULL, 'single_choice', '合於商業會計法第82條第2項中央主管機關核定之小規模合夥或獨資商業標準者有作假帳的行 為，是否依同法第71條之規定課其刑事責任？', '["應有第71條之適用", "應無第71條之適用", "非絕對不適用第71條", "由經濟部依具體個案認定"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "8104aa37b1dc", "answer_pdf_sha1": "742f65f5e350", "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0204", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "公司法、證券交易法與商業會計法", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00821', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'essay', '甲會計師於民國X3年3月20日將基隆公司民國X2年度財務報表之
查核報告交付該公司。民國 X3 年 4 月 15 日甲會計師於新聞報導得
知，檢調接獲檢舉指基隆公司，涉嫌從民國 X0 年到 X2 年間利用多
間子公司進行假交易，2 年多來疑掏空公司資產逾 10 億元。地檢署
承辦檢察官 X3 年 4 月 14 日指揮調查局市調處幹員，兵分多路搜索
公司及董事長、相關涉案人住所等地，查扣帳冊、合約等資料，並以
被告身分約談董事長、財務長等人，董事長並遭收押禁見。對此基隆
公司表示，公司一向合法經營，無涉及不法，會配合調查澄清誤會，
目前公司財務業務健全且正常。試問：依我國審計準則公報第 55 號
「期後事項」規定，甲會計師面臨此事件應如何處理？（10分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "一", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00822', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'essay', '甲公司經營電子零組件之製造與銷售，存貨係按成本與淨變現價值孰
低法衡量，其淨變現價值之會計估計係由會計系統例行性資料處理所
產生，會計估計程序已妥善設計、付諸實行及維持。假如你是甲公司
的查核人員，於複核前期之類似會計估計後，認為管理階層當期之會
計估計程序可能為有效，依我國審計準則公報第 56 號「會計估計與
相關揭露之查核」規定，說明適當之查核因應對策。（12分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "二", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00823', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'essay', '甲公司因持有乙公司的100%之流通在外普通股，對乙公司具有控制
力，而依規定編製範圍涵蓋甲、乙二公司之集團財務報表。甲、乙二
家公司的財務報表原分別委託子、丑二位會計師進行查核，且經考量
集團主辦會計師宜由集團中最終母公司之簽證會計師擔任，故子會計
師為查核集團財務報表之集團主辦會計師。請依我國審計準則公報第
54號「集團財務報表查核之特別考量」規定，回答下列問題：
子會計師為查核集團財務報表應承擔之責任為何？並說明其如何
判斷乙公司係屬集團之重要組成個體與否？（5分）
在何種情況下，集團查核團隊不得採用組成個體查核人員的工作？
（5分）
無論集團查核報告是否提及組成個體查核人員之查核，集團查核
團隊瞭解組成個體查核人員時，應對那些事項取得瞭解？（5分）', '[]'::jsonb, 0, NULL, FALSE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T04:29:10+00:00", "source_pdf_sha1": "581935a3015c", "answer_pdf_sha1": null, "source_family": "moex-gov-tw", "moex": {"exam_code": "107140", "c": "803", "s": "0201", "q": "1"}, "raw_section_label": "甲、申論題部分", "subject": "審計學", "year": "107", "exam_name": "107年專門職業及技術人員高等考試會計師、不動產估價師、專利師、民間之公證人考試", "original_question_number": "三", "answer_corrected": false, "flags": [], "slug": "accountant", "db_exam_id": "cpa"}'::jsonb, NULL),
  ('cpa-moex-00824', 'cpa', 'cpa-moex-107-0e802df0', 'sub-cpa-03', NULL, 'essay', '高雄公司X1年財務報表係由臺南會計師事務所甲會計師簽證，高雄
